VALUES
  ('locality-e9ff7ca9-moex-00055', 'locality-e9ff7ca9', 'locality-e9ff7ca9-moex-114-3082b5f1', 'sub-locality-e9ff7ca9-03', NULL, 'single_choice', '甲為公益團體，認為A工廠長年違法傾倒廢棄物，致使周遭農地受到污染，遂依廢棄物清理法規 定，以書面向當地主管機關乙請求依法行使公權力。若乙未在法定期間內採取任何作為，而甲欲 依行政訴訟法規定提起公益訴訟時，下列敘述何者正確？ 本案仍應視其具體主張而提起特定訴訟類型 甲必須證明自身權益亦遭受損害，始得提起本案訴訟 向行政法院提起訴訟前，一律須經訴願程序 此種訴訟屬於備位性質，必須限於無法提起其他行政訴訟時，始得提起', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:22+00:00", "source_pdf_sha1": "91bb7df14e6a", "answer_pdf_sha1": "131e6ee68ca1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "501", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "locality", "civil_category": "客家事務行政"}'::jsonb, NULL),
  ('locality-e9ff7ca9-moex-00056', 'locality-e9ff7ca9', 'locality-e9ff7ca9-moex-114-3082b5f1', 'sub-locality-e9ff7ca9-03', NULL, 'single_choice', '關於行政訴訟制度之敘述，下列何者正確？ 提起一般給付訴訟應經訴願先行程序 提起都市計畫審查程序應向都市計畫區所在地之高等行政法院為之 公職人員選舉罷免法明定之選舉訴訟係向行政法院提起 不服律師懲戒委員會作成之懲戒處分係向行政法院提起訴訟', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:22+00:00", "source_pdf_sha1": "91bb7df14e6a", "answer_pdf_sha1": "131e6ee68ca1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "501", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "locality", "civil_category": "客家事務行政"}'::jsonb, NULL),
  ('locality-e9ff7ca9-moex-00057', 'locality-e9ff7ca9', 'locality-e9ff7ca9-moex-114-3082b5f1', 'sub-locality-e9ff7ca9-03', NULL, 'single_choice', '關於賠償義務機關，下列敘述何者正確？ 公共設施委託民間團體管理時，因管理欠缺致人民生命受有損害者，以該民間團體為賠償義務 機關 受託行使公權力之團體，其執行職務之人於行使公權力時所生之國家賠償責任，以該團體為賠 償義務機關 賠償義務機關經裁撤或改組者，原則上應優先以其裁撤或改組前之上級機關為賠償義務機關 無法確定賠償義務機關而請求上級機關確定，上級機關逾期不為確定者，得逕以該上級機關為 賠償義務機關', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:22+00:00", "source_pdf_sha1": "91bb7df14e6a", "answer_pdf_sha1": "131e6ee68ca1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "501", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "locality", "civil_category": "客家事務行政"}'::jsonb, NULL),
  ('locality-e9ff7ca9-moex-00058', 'locality-e9ff7ca9', 'locality-e9ff7ca9-moex-114-3082b5f1', 'sub-locality-e9ff7ca9-03', NULL, 'single_choice', '下列何種情形，國家應負損害賠償責任？ 各級政府機關依中央流行疫情指揮中心指揮官之指示，徵用私立醫療機構設立檢疫場所 既成道路或都市計畫道路用地，在依法徵收或價購前所埋設之地下設施，致妨礙土地權利人對 其權利之行使 私人建築物被指定為古蹟，致所有權人無法為使用收益 土地因地政機關登記遺漏，致人民無法主張權利', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:22+00:00", "source_pdf_sha1": "91bb7df14e6a", "answer_pdf_sha1": "131e6ee68ca1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "501", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "locality", "civil_category": "客家事務行政"}'::jsonb, NULL),
